const { generateId } = require('../../lib/id');

let projectsStore = [];

async function createProject(name) {
  const project = { id: generateId(), name };
  projectsStore.push(project);
  return project;
}

async function getAllProjects() {
  return projectsStore;
}

module.exports = { createProject, getAllProjects };

const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_TITLE', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let tasksStore = [];

async function createTask(projectId, title) {
  const task = { id: generateId(), projectId, title, status: 'todo' };
  tasksStore.push(task);
  return task;
}

async function getTasks(projectId, status) {
  let tasks = tasksStore.filter(task => task.projectId === projectId);
  if (status === 'done') {
    tasks = tasks.filter(task => task.status === 'done');
  }
  return tasks;
}

module.exports = { createTask, getTasks };

const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  try {
    const members = await membersService.getMembers(req.params.projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let membersStore = [];

async function addMember(projectId, userId, role) {
  const member = { id: generateId(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

async function getMembers(projectId) {
  return membersStore.filter(member => member.projectId === projectId);
}

module.exports = { addMember, getMembers };
const __botEvalMembersDupGuard = module.exports.addMember;
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const existing = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  if (Array.isArray(existing) && existing.some(member => member && String(member.userId || '') === userKey)) {
    return null;
  }
  if (typeof __botEvalMembersDupGuard === 'function') {
    return __botEvalMembersDupGuard(projectId, userId, role);
  }
  return null;
};

const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }
  try {
    const comment = await commentsService.addComment(req.params.projectId, req.params.taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  try {
    const comments = await commentsService.getComments(req.params.projectId, req.params.taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let commentsStore = [];

async function addComment(projectId, taskId, message) {
  const comment = { id: generateId(), projectId, taskId, message };
  commentsStore.push(comment);
  return comment;
}

async function getComments(projectId, taskId) {
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

module.exports = { addComment, getComments };

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = { sendError };

const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
